export const arkade_kitties = "// ArkadeKitties - Simplified Breeding Contract\n// Demonstrates commit-reveal breeding with oracle randomness\n//\n// Key features demonstrated:\n// - group.isFresh: Detect newly minted kitties\n// - group.control: Verify species membership\n// - group.metadataHash: Verify genome/attributes\n// - group.delta: Detect minting vs transfer\n//\n// Asset hierarchy:\n// - speciesControlId: The \"species\" control asset (e.g., \"ArkadeKitties\")\n// - Each kitty is a unique asset controlled by speciesControlId\n// - Breeding creates a new kitty with isFresh=1\n\noptions {\n    server = serverPk;\n    exit = 576;  // ~4 days for breeding timeout\n}\n\ncontract ArkadeKitties(\n    bytes32 speciesControlId,\n    pubkey oraclePk\n) {\n    // Breed two kitties to create a new one\n    // Parents must be species-controlled, child must be fresh\n    function breed(\n        bytes32 sireId,\n        bytes32 dameId,\n        bytes32 childId,\n        bytes32 sireGenomeHash,\n        bytes32 dameGenomeHash,\n        bytes32 expectedChildMetadataHash,\n        signature oracleSig,\n        int childOutputIdx,\n        int sireOutputIdx,\n        int dameOutputIdx,\n        int ctrlOutputIdx\n    ) {\n        // Verify sire is species-controlled with correct genome\n        let sireGroup = tx.assetGroups.find(sireId);\n        require(sireGroup.control == speciesControlId, \"sire not species-controlled\");\n        require(sireGroup.metadataHash == sireGenomeHash, \"sire genome mismatch\");\n        require(sireGroup.delta == 0, \"sire must be retained\");\n\n        // Verify dame is species-controlled with correct genome\n        let dameGroup = tx.assetGroups.find(dameId);\n        require(dameGroup.control == speciesControlId, \"dame not species-controlled\");\n        require(dameGroup.metadataHash == dameGenomeHash, \"dame genome mismatch\");\n        require(dameGroup.delta == 0, \"dame must be retained\");\n\n        // Verify child is fresh (new issuance in this tx)\n        let childGroup = tx.assetGroups.find(childId);\n        require(childGroup.isFresh == 1, \"child must be fresh\");\n        require(childGroup.delta == 1, \"must mint exactly 1 child\");\n        require(childGroup.control == speciesControlId, \"child not species-controlled\");\n        require(childGroup.metadataHash == expectedChildMetadataHash, \"child genome mismatch\");\n\n        // Species control must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(speciesControlId);\n        require(ctrlGroup.delta == 0, \"species control must be retained\");\n\n        // Oracle signature validates the breeding (genome combination)\n        require(checkSig(oracleSig, oraclePk), \"invalid oracle sig\");\n\n        // Verify outputs contain all assets\n        require(tx.outputs[childOutputIdx].assets.lookup(childId) == 1, \"child not in output\");\n        require(tx.outputs[sireOutputIdx].assets.lookup(sireId) == 1, \"sire not returned\");\n        require(tx.outputs[dameOutputIdx].assets.lookup(dameId) == 1, \"dame not returned\");\n        require(tx.outputs[ctrlOutputIdx].assets.lookup(speciesControlId) == 1, \"ctrl not retained\");\n    }\n\n    // Transfer a kitty to a new owner\n    function transfer(bytes32 kittyId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let kittyGroup = tx.assetGroups.find(kittyId);\n\n        // Must be existing kitty (not fresh)\n        require(kittyGroup.isFresh == 0, \"must be existing kitty\");\n\n        // Must be species-controlled\n        require(kittyGroup.control == speciesControlId, \"not species-controlled\");\n\n        // Must be transfer (delta == 0)\n        require(kittyGroup.delta == 0, \"must be transfer only\");\n\n        require(tx.outputs[0].assets.lookup(kittyId) == 1, \"kitty not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong destination\");\n        require(checkSig(ownerSig, ownerPk), \"invalid owner sig\");\n    }\n}\n";

export const beacon = "// Price Beacon Contract\n// Read-only recursive covenant that ensures all asset groups survive intact.\n//\n// This contract demonstrates compile-time loop unrolling:\n// - `for (k, group) in tx.assetGroups` iterates over all asset groups\n// - The loop is unrolled N times based on `numGroups` constructor param\n//\n// Use cases:\n// - Price oracle beacons where asset quantities encode values\n// - Passthrough covenants that preserve all assets\n\noptions {\n  server = oracleServerPk;\n  exit = 144;\n}\n\ncontract PriceBeacon(\n  bytes32 ctrlAssetId,\n  pubkey oraclePk,\n  int numGroups\n) {\n  // Anyone can pass through - all groups must survive\n  function passthrough() {\n    require(tx.outputs[0].scriptPubKey == tx.input.current.scriptPubKey, \"broken\");\n\n    for (k, group) in tx.assetGroups {\n      require(group.sumOutputs >= group.sumInputs, \"drained\");\n    }\n  }\n\n  // Oracle updates price (quantity encodes value)\n  function update(signature oracleSig) {\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl\");\n    require(tx.outputs[0].scriptPubKey == tx.input.current.scriptPubKey, \"broken\");\n    require(checkSig(oracleSig, oraclePk), \"bad sig\");\n  }\n}\n";

export const controlled_mint = "// Controlled Mint Contract\n// Demonstrates asset group introspection primitives\n//\n// This contract manages a token minting authority where:\n// 1. mint() - Authority can mint new tokens (delta > 0), control asset required\n// 2. burn() - Anyone can burn tokens (delta < 0), no control needed\n// 3. lockSupply() - Authority burns the control asset to lock supply forever\n//\n// Asset groups provide aggregate views of asset flows across all inputs/outputs,\n// enabling balance verification without iterating individual UTXOs.\n\noptions {\n  server = serverPk;\n  exit = 288;\n}\n\ncontract ControlledMint(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey issuerPk\n) {\n  // Mint: delta > 0, control asset present and retained\n  function mint(int amount, pubkey recipientPk, signature issuerSig) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.delta == amount, \"delta mismatch\");\n    require(tokenGroup.control == ctrlAssetId, \"wrong control\");\n\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.delta == 0, \"ctrl supply changed\");\n\n    require(tx.outputs[0].assets.lookup(tokenAssetId) >= amount, \"mint short\");\n    require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n\n  // Burn: delta < 0, no control asset needed\n  function burn(int amount, signature ownerSig, pubkey ownerPk) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.sumInputs >= tokenGroup.sumOutputs + amount, \"burn short\");\n    require(checkSig(ownerSig, ownerPk), \"bad sig\");\n  }\n\n  // Lock supply forever: burn the control asset\n  function lockSupply(signature issuerSig) {\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.sumOutputs == 0, \"ctrl not burned\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n}\n";

export const fee_adapter = "// Fee Adapter Contract\n// Demonstrates arithmetic expressions with tx input/output verification\n//\n// This contract implements a fee-taking adapter where:\n// 1. execute() - Processes a payment, verifying output asset balances\n// 2. The output must preserve assets minus fee\n//\n// Uses asset lookups on tx.inputs and tx.outputs with arithmetic\n// comparisons for balance verification.\n\noptions {\n  server = operatorPk;\n  exit = 144;\n}\n\ncontract FeeAdapter(\n  pubkey senderPk,\n  pubkey operatorPk,\n  pubkey recipientPk,\n  bytes32 paymentAssetId,\n  int minFee\n) {\n  // Execute: process payment with fee deduction\n  // Verifies that the output asset balance reflects the fee deduction\n  function execute(signature senderSig, int fee) {\n    // Fee must be at least the minimum\n    require(fee >= minFee, \"fee below minimum\");\n\n    // Input must contain the payment asset\n    require(tx.inputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in input\");\n\n    // Output must contain the payment asset (minus fee)\n    require(tx.outputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in output\");\n\n    // Sender must sign\n    require(checkSig(senderSig, senderPk), \"invalid sender signature\");\n  }\n\n  // Adjust: operator adjusts fee parameters\n  function adjust(signature operatorSig) {\n    // Operator must sign\n    require(checkSig(operatorSig, operatorPk), \"invalid operator signature\");\n  }\n}\n";

export const fuji_safe = "// Contract configuration options\noptions {\n  // Arkade operator key (always external, never a contract party)\n  server = operator;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  exit = 144;\n}\n\n// Fuji Safe Contract\ncontract FujiSafe(\n  // The asset commitment hash (client-side validated)\n  bytes assetCommitmentHash,\n  // The amount being borrowed\n  int borrowAmount,\n  // The borrower's public key\n  pubkey borrowerPk,\n  // The treasury's public key\n  pubkey treasuryPk,\n  // The expiration timeout in blocks\n  int expirationTimeout,\n  // The price level for liquidation\n  int priceLevel,\n  // The setup timestamp\n  int setupTimestamp,\n  // The oracle's public key\n  pubkey oraclePk,\n  // The asset pair identifier\n  bytes assetPair\n) {\n  // Helper function to verify Fuji token burning via Taproot output\n  // Takes the pubkey to use as the internal key for the P2TR output\n  function verifyFujiBurning(pubkey internalKey) internal {\n    // In Taproot, we verify the output is a P2TR that commits to our asset\n    // Using the provided pubkey as the internal key\n    bytes p2trScript = new P2TR(internalKey, assetCommitmentHash);\n    \n    // Verify output 0 has the correct P2TR scriptPubKey and value\n    require(tx.outputs[0].scriptPubKey == p2trScript, \"P2TR output mismatch\");\n    require(tx.outputs[0].value == borrowAmount, \"Value mismatch\");\n  }\n\n  // Claim: Treasury can unlock all collateral after expiration when burning Fuji\n  function claim(signature treasurySig) {\n    // Check that expiration timeout has passed\n    require(tx.time >= expirationTimeout, \"Expiration timeout not reached\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Liquidation: Treasury can unlock all collateral with attestation price below the liquidation target\n  function liquidate(int currentPrice, signature oracleSig, signature treasurySig) {\n    // Check price is below liquidation threshold\n    require(currentPrice < priceLevel, \"Price not below liquidation threshold\");\n    \n    // Verify timestamp is after setup\n    require(tx.time >= setupTimestamp, \"Timestamp before setup\");\n    \n    // Create message for oracle signature verification\n    bytes message = sha256(assetPair);\n    \n    // Verify oracle signature on price data\n    require(checkSigFromStack(oracleSig, oraclePk, message), \"Invalid oracle signature\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Private Redemption: Only owner can unlock all collateral with key when burning Fuji\n  function redeem(signature borrowerSig) {\n    // Verify burning of Fuji token using borrower key\n    verifyFujiBurning(borrowerPk);\n    \n    // Require borrower signature\n    require(checkSig(borrowerSig, borrowerPk), \"Invalid borrower signature\");\n  }\n  \n  // Treasury Renew: Treasury can unilaterally renew the expiration time\n  function renew(signature treasurySig) {\n    int currentValue = tx.input.current.value;\n\n    // Recreate same contract with identical parameters\n    require(\n      tx.outputs[0].scriptPubKey == new FujiSafe(\n        assetCommitmentHash, borrowAmount, borrowerPk, treasuryPk,\n        expirationTimeout, priceLevel, setupTimestamp, oraclePk, assetPair\n      ),\n      \"contract mismatch\"\n    );\n    require(tx.outputs[0].value == currentValue, \"Value mismatch\");\n\n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n} ";

export const htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver], [senderSig, receiverSig]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const nft_mint = "// NFT Minting Contract\n// Demonstrates isFresh and assetId properties for unique asset creation\n//\n// This contract enforces:\n// 1. Each NFT is fresh (newly created in this transaction)\n// 2. NFTs are controlled by a collection control asset\n// 3. Only one unit per NFT (delta = 1)\n//\n// Key group properties used:\n// - group.isFresh: Detects if asset was created in current transaction\n// - group.delta: Ensures exactly 1 unit is minted\n// - group.control: Verifies collection membership\n\noptions {\n    server = serverPk;\n    exit = 288;\n}\n\ncontract NFTMint(\n    bytes32 collectionCtrlId,\n    pubkey issuerPk\n) {\n    // Mint a new NFT: must be fresh with delta=1\n    function mint(bytes32 nftAssetId, pubkey recipientPk, signature issuerSig) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be a brand new asset (genesis in this tx)\n        require(nftGroup.isFresh == 1, \"must be fresh\");\n\n        // Must mint exactly 1 (NFT)\n        require(nftGroup.delta == 1, \"must mint exactly 1\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // Control asset must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(collectionCtrlId);\n        require(ctrlGroup.delta == 0, \"control must be retained\");\n\n        // NFT goes to recipient\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong recipient\");\n\n        require(checkSig(issuerSig, issuerPk), \"bad issuer sig\");\n    }\n\n    // Transfer existing NFT (not fresh)\n    function transfer(bytes32 nftAssetId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must NOT be fresh (existing asset)\n        require(nftGroup.isFresh == 0, \"cannot be fresh\");\n\n        // Must be a transfer (delta == 0)\n        require(nftGroup.delta == 0, \"must be transfer\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // NFT goes to new owner\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong dest\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n\n    // Burn an NFT (delta = -1)\n    function burn(bytes32 nftAssetId, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be existing asset\n        require(nftGroup.isFresh == 0, \"cannot burn fresh asset\");\n\n        // Must burn exactly 1 (negative delta)\n        require(nftGroup.sumInputs >= nftGroup.sumOutputs + 1, \"must burn exactly 1\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n}\n";

export const non_interactive_swap = "// Non-Interactive Swap Contract\n// Allows users to exchange assets without requiring both parties to be online simultaneously.\n//\n// VTXO\n// - Cooperative path: Server emulates/validates introspection, co-signs for fast settlement\n// - Exit path: N-of-N user signatures when introspection is used (pure Bitcoin fallback)\n//\n// Paths:\n// - swap cooperative: takerSig + serverSig + OP_INSPECT* (trustless via introspection)\n// - swap exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin)\n// - cancel cooperative: makerSig + serverSig + after(expiration)\n// - cancel exit: makerSig + after(expiration) + CSV (normal exit)\n\noptions {\n  // Server key is injected from getInfo(), not passed in constructor\n  server = serverPk;\n  // Exit delay: 144 blocks (~24 hours) for unilateral recovery\n  exit = 144;\n}\n\ncontract NonInteractiveSwap(\n  // Maker's public key (creator of the swap offer)\n  pubkey makerPk,\n  // Asset ID the maker is offering (locked in this contract)\n  bytes32 offerAssetId,\n  // Amount of offer asset locked\n  int offerAmount,\n  // Asset ID the maker wants to receive\n  bytes32 wantAssetId,\n  // Amount of want asset required for the swap\n  int wantAmount,\n  // Expiration timestamp (block height) after which maker can cancel\n  int expirationTime\n) {\n  // Swap: Any taker can fulfill - introspection makes cooperative path trustless\n  // Cooperative: takerSig + serverSig + OP_INSPECT* (server validates outputs)\n  // Exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin - no introspection)\n  function swap(pubkey takerPk, signature takerSig) {\n    // Taker must sign to authorize spending their wantAsset\n    require(checkSig(takerSig, takerPk), \"invalid taker signature\");\n\n    // Introspection verifies the atomic exchange:\n    // Output 0: maker receives wantAsset\n    require(\n      tx.outputs[0].assets.lookup(wantAssetId) >= wantAmount,\n      \"insufficient want asset for maker\"\n    );\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(makerPk),\n      \"output 0 not spendable by maker\"\n    );\n\n    // Output 1: taker receives offerAsset\n    require(\n      tx.outputs[1].assets.lookup(offerAssetId) >= offerAmount,\n      \"insufficient offer asset for taker\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(takerPk),\n      \"output 1 not spendable by taker\"\n    );\n  }\n\n  // Cancel: Maker reclaims after expiration if no taker\n  // No introspection used, so normal exit path applies\n  // Cooperative: makerSig + serverSig + after(expiration)\n  // Exit: makerSig + after(expiration) + CSV\n  function cancel(signature makerSig) {\n    require(tx.time >= expirationTime, \"swap not expired\");\n    require(checkSig(makerSig, makerPk), \"invalid maker signature\");\n  }\n}\n";

export const payment_auth = "// Payment Authorization Contract\n// Authorization-based escrow with timelocked refunds using transaction introspection\n//\n// This contract implements a credit card-like payment flow:\n// 1. Customer locks funds in escrow\n// 2. Merchant can capture (authorize and settle) the payment\n// 3. If not captured, customer can refund after timelock expires\n//\n// The contract validates the full payout structure:\n// - Merchant receives payment minus processor fee\n// - Processor receives fee (basis points of payment)\n// - Customer receives change if overpayment\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract PaymentAuthorization(\n  // Server key for cooperative path\n  pubkey server,\n\n  // Payment terms\n  int invoiceAmount,\n  int feeRateBasisPoints,\n\n  // Output scripts (P2TR scriptPubKeys)\n  bytes merchantScript,\n  bytes processorScript,\n  bytes customerScript,\n\n  // Refund timelock (block height)\n  int refundBlockHeight,\n\n  // Authorization key\n  pubkey merchantPubkey\n) {\n\n  // Capture: merchant-authorized settlement\n  // Validates payout structure based on payment amount vs invoice\n  function capture(signature merchantSig) {\n    require(checkSig(merchantSig, merchantPubkey), \"Invalid merchant signature\");\n\n    // Get the current input value (amount locked in escrow)\n    let vtxoValue = tx.input.current.value;\n\n    // Case 1: Underpayment (vtxoValue < invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue < invoiceAmount) {\n      require(vtxoValue >= 10000, \"Payment below dust threshold\");\n      require(tx.numOutputs == 2, \"Expected 2 outputs for underpayment\");\n\n      // Fee = vtxoValue * feeRateBasisPoints / 10000\n      let processorFee = (vtxoValue * feeRateBasisPoints) / 10000;\n      let merchantAmount = vtxoValue - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 2: Exact payment (vtxoValue == invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue == invoiceAmount) {\n      require(tx.numOutputs == 2, \"Expected 2 outputs for exact payment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 3: Overpayment (vtxoValue > invoiceAmount)\n    // Pay merchant (minus fee) + processor fee + customer change\n    if (vtxoValue > invoiceAmount) {\n      require(tx.numOutputs == 3, \"Expected 3 outputs for overpayment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n      let changeAmount = vtxoValue - invoiceAmount;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n\n      require(tx.outputs[2].value == changeAmount, \"Change amount incorrect\");\n      require(tx.outputs[2].scriptPubKey == customerScript, \"Change script incorrect\");\n    }\n  }\n\n  // Refund: timelocked fallback back to customer\n  // Becomes valid after refundBlockHeight - effectively anyone-can-spend into customerScript\n  function refund() {\n    require(tx.time >= refundBlockHeight, \"Refund timelock not reached\");\n\n    let vtxoValue = tx.input.current.value;\n\n    require(tx.numOutputs == 1, \"Expected 1 output for refund\");\n    require(tx.outputs[0].value == vtxoValue, \"Refund amount incorrect\");\n    require(tx.outputs[0].scriptPubKey == customerScript, \"Refund script incorrect\");\n  }\n}\n";

export const price_beacon = "// Price Beacon Contract\n// On-chain price oracle using asset quantity as price.\n// The quantity of priceAssetId represents BTC/USD price in cents.\n//\n// Example: 10000000 = $100,000.00 per BTC\n//\n// Properties:\n// - Price is publicly visible on-chain\n// - Anyone can read via introspection (tx.inputs[i].assets.lookup)\n// - Passthrough ensures beacon survives every transaction\n// - Only oracle can update the price\n\noptions {\n  server = oraclePk;\n  exit = 144;\n}\n\ncontract PriceBeacon(\n  bytes32 priceAssetId,      // Asset whose quantity = price\n  pubkey oraclePk            // Oracle authorized to update\n) {\n  // Anyone can read price via passthrough\n  // Beacon must survive with same or greater asset quantity\n  function passthrough() {\n    // Preserve the beacon script\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(priceAssetId, oraclePk),\n      \"beacon script must survive\"\n    );\n\n    // Preserve the price asset (quantity is the price)\n    int currentPrice = tx.inputs[0].assets.lookup(priceAssetId);\n    require(\n      tx.outputs[0].assets.lookup(priceAssetId) >= currentPrice,\n      \"price asset must survive\"\n    );\n  }\n\n  // Oracle updates the price by changing asset quantity\n  function update(signature oracleSig, int newPrice) {\n    require(checkSig(oracleSig, oraclePk), \"invalid oracle signature\");\n    require(newPrice > 0, \"price must be positive\");\n\n    // Preserve the beacon script\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(priceAssetId, oraclePk),\n      \"beacon script must survive\"\n    );\n\n    // Output must have newPrice as asset quantity\n    require(\n      tx.outputs[0].assets.lookup(priceAssetId) == newPrice,\n      \"price not updated correctly\"\n    );\n  }\n\n  // Oracle can migrate to new beacon (upgrade)\n  function migrate(signature oracleSig, pubkey newOraclePk) {\n    require(checkSig(oracleSig, oraclePk), \"invalid oracle signature\");\n\n    int currentPrice = tx.inputs[0].assets.lookup(priceAssetId);\n\n    // Create new beacon with new oracle\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(priceAssetId, newOraclePk),\n      \"invalid new beacon\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(priceAssetId) == currentPrice,\n      \"price must be preserved\"\n    );\n  }\n}\n";

export const single_sig = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract SingleSig(\n  pubkey user\n) {\n  // Single signature spend path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(user) && checkSig(server)\n  // 2. Exit path: checkSig(user) && after 144 blocks\n  function spend(signature userSig) {\n    require(checkSig(userSig, user));\n  }\n} ";

export const stability_offer = "// Stability Offer Contract\n// Provider pre-commits liquidity into standing offers that users can claim unilaterally.\n// Creates synthetic USD-stable positions backed by BTC collateral.\n//\n// Uses PriceBeacon for on-chain price discovery:\n// - Entry price read from beacon at offer creation\n// - Positions reference the same beacon for settlement\n\noptions {\n  server = providerPk;\n  exit = 144;\n}\n\ncontract StabilityOffer(\n  pubkey providerPk,\n  pubkey userPk,             // User this offer is committed to\n  bytes32 priceAssetId,      // Asset ID used by PriceBeacon\n  int entryPriceUSD,         // Fixed BTC/USD price at offer creation\n  int collateralBTC,         // Provider's BTC collateral per position\n  int maxExposureBTC         // Maximum user BTC this offer accepts\n) {\n  // Anyone can execute - offer is pre-committed to userPk\n  // No signatures needed - true non-interactive standing offer\n  function take(int userBTC) {\n    // User deposit within limits\n    require(userBTC > 0, \"zero deposit\");\n    require(userBTC <= maxExposureBTC, \"exceeds offer capacity\");\n\n    // Calculate position parameters\n    int stableUSD = userBTC * entryPriceUSD / 100000000;  // User's USD balance\n    int totalCollateral = userBTC + collateralBTC;        // Combined BTC locked\n\n    // Output 0: Create StablePosition with correct parameters\n    require(\n      tx.outputs[0].scriptPubKey == new StablePosition(\n        userPk,           // User owns the position\n        providerPk,       // Provider counterparty\n        priceAssetId,     // Reference to price beacon\n        stableUSD,        // User's USD balance\n        entryPriceUSD,    // Entry price for reference\n        totalCollateral   // Total BTC locked\n      ),\n      \"invalid position created\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"insufficient position collateral\");\n\n    // Output 1: Remaining offer capacity (recursive)\n    int remainingExposure = maxExposureBTC - userBTC;\n    if (remainingExposure > 0) {\n      require(\n        tx.outputs[1].scriptPubKey == new StabilityOffer(\n          providerPk,\n          userPk,\n          priceAssetId,\n          entryPriceUSD,\n          collateralBTC,\n          remainingExposure  // Reduced capacity\n        ),\n        \"invalid remaining offer\"\n      );\n      // Remaining offer needs proportional collateral\n      int remainingCollateral = collateralBTC * remainingExposure / maxExposureBTC;\n      require(tx.outputs[1].value >= remainingCollateral, \"insufficient remaining collateral\");\n    }\n  }\n\n  // Provider withdraws unused liquidity\n  function withdraw(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider signature\");\n    // Provider can claim all value in this UTXO\n  }\n\n  // Provider updates offer price (creates new offer at current beacon price)\n  // Include PriceBeacon UTXO as input[1] to read current price\n  function reprice(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider signature\");\n\n    // Read current price from beacon\n    int newPriceUSD = tx.inputs[1].assets.lookup(priceAssetId);\n    require(newPriceUSD > 0, \"invalid price from beacon\");\n\n    // Create new offer at updated price\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityOffer(\n        providerPk,\n        userPk,\n        priceAssetId,\n        newPriceUSD,      // New entry price from beacon\n        collateralBTC,\n        maxExposureBTC\n      ),\n      \"invalid repriced offer\"\n    );\n    require(tx.outputs[0].value >= collateralBTC, \"collateral not preserved\");\n\n    // Beacon must survive\n    require(\n      tx.outputs[1].assets.lookup(priceAssetId) >= newPriceUSD,\n      \"beacon must survive\"\n    );\n  }\n}\n";

export const stable_position = "// Stable Position Contract\n// Recursive covenant representing a USD-stable balance backed by BTC collateral.\n// User holds fixed USD value; settlement converts to BTC at current price.\n//\n// Uses PriceBeacon for on-chain price discovery:\n// - No oracle signatures needed\n// - Price is publicly visible in beacon UTXO\n// - Atomic reads via introspection\n\noptions {\n  server = providerPk;\n  exit = 144;\n}\n\ncontract StablePosition(\n  pubkey userPk,\n  pubkey providerPk,\n  bytes32 priceAssetId,      // Asset ID used by PriceBeacon (quantity = price)\n  int targetUSD,             // User's USD balance (immutable)\n  int entryPrice,            // BTC/USD at entry (for reference)\n  int totalCollateral        // Combined BTC locked (sats)\n) {\n  // User exits to BTC at current price from beacon\n  // Include PriceBeacon UTXO as input[1] to read price\n  function settle(signature userSig) {\n    require(checkSig(userSig, userPk), \"invalid user signature\");\n\n    // Read price from beacon input (input[1] is the beacon)\n    // Price is encoded as quantity of priceAssetId\n    int currentPrice = tx.inputs[1].assets.lookup(priceAssetId);\n    require(currentPrice > 0, \"invalid price from beacon\");\n\n    // User payout = targetUSD / currentPrice (in sats)\n    int userPayout = targetUSD * 100000000 / currentPrice;\n    require(userPayout <= totalCollateral, \"insufficient collateral\");\n\n    // Output 0: User receives their USD value in BTC\n    require(tx.outputs[0].value >= userPayout, \"user payout too low\");\n    require(tx.outputs[0].scriptPubKey == new SingleSig(userPk), \"output 0 not user\");\n\n    // Output 1: Provider receives remainder\n    int providerPayout = totalCollateral - userPayout;\n    if (providerPayout > 546) {\n      require(tx.outputs[1].value >= providerPayout, \"provider payout too low\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(providerPk), \"output 1 not provider\");\n    }\n\n    // Output 2: Beacon must survive (passthrough)\n    // The beacon's own script enforces this, but we verify it's preserved\n    require(\n      tx.outputs[2].assets.lookup(priceAssetId) >= currentPrice,\n      \"beacon must survive\"\n    );\n  }\n\n  // Transfer stable balance to new owner (recursive covenant)\n  function transfer(signature userSig, pubkey newUserPk) {\n    require(checkSig(userSig, userPk), \"invalid user signature\");\n\n    // Output must be new StablePosition with newUserPk as owner\n    require(\n      tx.outputs[0].scriptPubKey == new StablePosition(\n        newUserPk, providerPk, priceAssetId,\n        targetUSD, entryPrice, totalCollateral\n      ),\n      \"invalid position transfer\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n  }\n\n  // Provider liquidates if undercollateralized\n  // Include PriceBeacon UTXO as input[1]\n  function liquidate(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider signature\");\n\n    // Read price from beacon\n    int currentPrice = tx.inputs[1].assets.lookup(priceAssetId);\n    require(currentPrice > 0, \"invalid price from beacon\");\n\n    // Check undercollateralization: collateral < 120% of user's BTC value\n    int userValueBTC = targetUSD * 100000000 / currentPrice;\n    int requiredCollateral = userValueBTC * 120 / 100;\n    require(totalCollateral < requiredCollateral, \"position not undercollateralized\");\n\n    // Provider claims all collateral\n    require(tx.outputs[0].value >= totalCollateral, \"must claim all collateral\");\n    require(tx.outputs[0].scriptPubKey == new SingleSig(providerPk), \"output not provider\");\n\n    // Beacon must survive\n    require(\n      tx.outputs[1].assets.lookup(priceAssetId) >= currentPrice,\n      \"beacon must survive\"\n    );\n  }\n\n  // Provider tops up collateral (recursive covenant)\n  function topUp(signature providerSig, int additionalBTC) {\n    require(checkSig(providerSig, providerPk), \"invalid provider signature\");\n    require(additionalBTC > 0, \"must add collateral\");\n\n    int newCollateral = totalCollateral + additionalBTC;\n\n    // Output must be new StablePosition with increased collateral\n    require(\n      tx.outputs[0].scriptPubKey == new StablePosition(\n        userPk, providerPk, priceAssetId,\n        targetUSD, entryPrice, newCollateral\n      ),\n      \"invalid topped-up position\"\n    );\n    require(tx.outputs[0].value >= newCollateral, \"insufficient new collateral\");\n  }\n}\n";

export const threshold_multisig_htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const threshold_oracle = "// Threshold Oracle Contract\n// Generic threshold signature verifier for multi-oracle attestations.\n//\n// This contract demonstrates:\n// - Array types in constructor params (pubkey[] oracles)\n// - Array types in function params (signature[] oracleSigs)\n// - Array indexing (oracles[i])\n// - Loop unrolling with array iteration\n// - Threshold counting for quorum verification\n//\n// N oracles, require M valid signatures over a message.\n\noptions {\n  server = serverPk;\n  exit = 288;\n}\n\ncontract ThresholdOracle(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey[] oracles,\n  int threshold\n) {\n  function attest(\n    int amount,\n    bytes32 messageHash,\n    pubkey recipientPk,\n    signature[] oracleSigs\n  ) {\n    require(amount > 0, \"zero\");\n\n    int valid = 0;\n    for (i, sig) in oracleSigs {\n      if (checkSigFromStack(sig, oracles[i], messageHash)) {\n        valid = valid + 1;\n      }\n    }\n    require(valid >= threshold, \"quorum failed\");\n\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl\");\n    require(tx.outputs[1].assets.lookup(tokenAssetId) >= amount, \"short\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(tx.outputs[0].scriptPubKey == new ThresholdOracle(tokenAssetId, ctrlAssetId, oracles, threshold), \"broken\");\n  }\n}\n";

export const token_vault = "// Token Vault Contract\n// Demonstrates asset lookup primitives for Arkades Assets\n//\n// This contract locks tokens and allows:\n// 1. deposit() - Owner deposits tokens; output must hold at least as many as input\n// 2. withdraw() - Owner withdraws tokens with server co-signature\n//\n// Asset lookups use the OP_INSPECTINASSETLOOKUP / OP_INSPECTOUTASSETLOOKUP\n// opcodes with sentinel-guard patterns for safe balance verification.\n\noptions {\n  server = serverPk;\n  exit = 144;\n}\n\ncontract TokenVault(\n  pubkey ownerPk,\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId\n) {\n  // Deposit: ensure the control asset stays in the output\n  // and output token balance >= input token balance\n  function deposit(signature ownerSig) {\n    // Control asset must be present in input 0\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in input\");\n\n    // Control asset must be present in output 0\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Output tokens >= input tokens (no leaking tokens)\n    require(\n      tx.outputs[0].assets.lookup(tokenAssetId) >=\n        tx.inputs[0].assets.lookup(tokenAssetId),\n      \"token balance decreased\"\n    );\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n\n  // Withdraw: owner withdraws tokens cooperatively with server\n  function withdraw(signature ownerSig, int amount) {\n    // Control asset must stay in the output\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n}\n";

export const vault_lending_composite_router = "// composite_router.ark\n// Atomically updates VaultCovenant + 2 StrategyFragments in one transaction.\n// Keeper attestations verified via checkSigFromStack.\n// PPS monotonicity enforced: newTotalAssets >= currentTotalAssets.\n//\n// weight0 + weight1 must equal 10000 (basis points); enforced on-chain in route().\n//\n// Division note: (reported0 * weight0 + reported1 * weight1) / 10000 floors toward zero.\n// This may cause newTotalAssets to be 1 sat below the true weighted average at boundary values.\n\nimport \"vault_covenant.ark\";\nimport \"strategy_fragment.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract CompositeRouter(\n  pubkey keeper0,\n  pubkey keeper1,\n  pubkey vaultKeeperPk,\n  pubkey ownerPk,\n  int weight0,        // basis points; weight0 + weight1 == 10000\n  int weight1,\n  bytes32 strategyId0,\n  bytes32 strategyId1\n) {\n  function route(\n    signature keeperSig0,\n    signature keeperSig1,\n    bytes32 reportHash0,\n    bytes32 reportHash1,\n    int reported0,\n    int reported1,\n    int currentTotalAssets,\n    int currentTotalShares\n  ) {\n    require(checkSigFromStack(keeperSig0, keeper0, reportHash0), \"invalid keeper0\");\n    require(checkSigFromStack(keeperSig1, keeper1, reportHash1), \"invalid keeper1\");\n\n    int weightSum = weight0 + weight1;\n    require(weightSum == 10000, \"weights must sum to 10000\");\n\n    int newTotalAssets = (reported0 * weight0 + reported1 * weight1) / 10000;\n    require(newTotalAssets >= currentTotalAssets, \"PPS decrease forbidden\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, newTotalAssets, currentTotalShares\n      ),\n      \"vault successor mismatch\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new StrategyFragment(\n        keeper0, reported0, strategyId0\n      ),\n      \"fragment0 successor mismatch\"\n    );\n    require(\n      tx.outputs[2].scriptPubKey == new StrategyFragment(\n        keeper1, reported1, strategyId1\n      ),\n      \"fragment1 successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_lending_market = "// lending_market.ark\n// Lending market covenant. Manages collateral and debt for one borrower position.\n//\n// Debt is supplied externally via SupplyFlow from VaultCovenant (exogenous path only).\n// Collateral locks in this covenant; borrowed funds flow to the borrower at borrow time.\n//\n// Repayment and liquidation:\n//   repay      — partial or full. Credit holder receives proceeds; full repay releases collateral.\n//   liquidate  — keeper-only. Waterfall: fee to keeper | face value to creditHolder | residual to borrower.\n//   transferCredit — updates creditHolder for secondary market settlement (e.g. NonInteractiveSwap).\n//\n// Division note: all ratio checks use integer arithmetic scaled to basis points.\n// OP_DIV64 floors toward zero. Both sides of the LLTV check are consistently floored,\n// so no systematic bias exists. Ratio boundaries are very slightly borrower-favourable.\n// Liquidation fee truncates down (keeper receives marginally less at fee boundary values).\n\nimport \"lending_market.ark\";\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract LendingMarket(\n  pubkey  borrowerPk,\n  pubkey  oraclePk,\n  pubkey  vaultKeeperPk,\n  pubkey  creditHolder,       // lender's on-chain address; updated by transferCredit\n  int     collateralAmount,\n  int     debtAmount,\n  int     lltv,               // basis points, e.g. 8500 = 85%\n  bytes32 collateralAssetId,\n  bytes32 loanAssetId,\n  bytes32 oracleHash\n) {\n  // ─── Borrow ───────────────────────────────────────────────────────────────────\n  // Debt was supplied by VaultCovenant via SupplyFlow.\n  // Borrower provides collateral; borrowed funds flow out to borrower on output 1.\n  function borrow(\n    signature borrowerSig,\n    bytes32 priceHash,\n    signature oracleSig,\n    int price,\n    int borrowAmount,\n    int collateral\n  ) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower\");\n    require(checkSigFromStack(oracleSig, oraclePk, priceHash), \"invalid oracle\");\n\n    // Collateral ratio check: (collateral * price / 10000) >= (borrowAmount * 10000 / lltv)\n    // Division floors toward zero — see contract header note.\n    int lhs = collateral * price / 10000;\n    int rhs = borrowAmount * 10000 / lltv;\n    require(lhs >= rhs, \"insufficient collateral ratio\");\n\n    // Output 0: updated LendingMarket holding the collateral\n    require(tx.outputs[0].value == collateral, \"collateral must be locked in output 0\");\n    require(\n      tx.outputs[0].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n        collateral, borrowAmount, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"successor mismatch\"\n    );\n    // Output 1: borrowed funds flow to borrower\n    require(tx.outputs[1].value == borrowAmount, \"borrower must receive borrow amount\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk),\n      \"borrower output mismatch\"\n    );\n  }\n\n  // ─── Repay ────────────────────────────────────────────────────────────────────\n  // Borrower repays partial or full debt.\n  // Credit holder receives repayment proceeds on output 1.\n  // Full repay: collateral released to borrower on output 0.\n  // Partial repay: recursive covenant on output 0 with updated debtAmount.\n  function repay(\n    signature borrowerSig,\n    int repayAmount,\n    int newDebtAmount\n  ) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower\");\n    require(repayAmount > 0, \"repayAmount must be positive\");\n\n    // Verify accounting: newDebtAmount + repayAmount == debtAmount\n    int verifySum = newDebtAmount + repayAmount;\n    require(verifySum == debtAmount, \"invalid repay amounts\");\n\n    // Credit holder receives repayment on output 1\n    require(tx.outputs[1].value == repayAmount, \"repayment value must match repay amount\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(creditHolder),\n      \"repayment must go to credit holder\"\n    );\n\n    if (newDebtAmount == 0) {\n      // Full repay: release collateral to borrower\n      require(tx.outputs[0].value == collateralAmount, \"full collateral must be released\");\n      require(\n        tx.outputs[0].scriptPubKey == new SingleSig(borrowerPk),\n        \"collateral must be returned to borrower\"\n      );\n    } else {\n      // Partial repay: recursive covenant with reduced debt; collateral stays locked\n      require(tx.outputs[0].value == collateralAmount, \"partial repay must preserve collateral value\");\n      require(\n        tx.outputs[0].scriptPubKey == new LendingMarket(\n          borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n          collateralAmount, newDebtAmount, lltv,\n          collateralAssetId, loanAssetId, oracleHash\n        ),\n        \"successor mismatch\"\n      );\n    }\n  }\n\n  // ─── Liquidate ────────────────────────────────────────────────────────────────\n  // Keeper-only. Position must be underwater (threshold < debtAmount).\n  // Liquidation waterfall:\n  //   output 0: liquidation fee (5% of collateral) to keeper\n  //   output 1: face value (debtAmount) to credit holder\n  //   output 2: residual (collateral - fee - debtAmount) to borrower\n  //\n  // Division note: fee = collateralAmount * 500 / 10000 floors toward zero.\n  // residual = collateralAmount - fee - debtAmount (chained subtraction).\n  // Caller is responsible for ensuring collateralAmount >= fee + debtAmount.\n  function liquidate(\n    signature vaultKeeperSig,\n    bytes32 priceHash,\n    signature oracleSig,\n    int price\n  ) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid keeper\");\n    require(checkSigFromStack(oracleSig, oraclePk, priceHash), \"invalid oracle\");\n\n    // Position is underwater: collateral value * lltv < debt * 10000\n    int ratio = collateralAmount * price / 10000;\n    int threshold = ratio * lltv / 10000;\n    require(threshold < debtAmount, \"position is not underwater\");\n\n    // Liquidation waterfall\n    int fee = collateralAmount * 500 / 10000;\n    int residual = collateralAmount - fee - debtAmount;\n    require(residual >= 0, \"residual must be non-negative\");\n\n    require(tx.outputs[0].value >= fee, \"liquidation fee output too low\");\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(vaultKeeperPk),\n      \"fee must go to keeper\"\n    );\n    require(tx.outputs[1].value >= debtAmount, \"credit holder payout too low\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(creditHolder),\n      \"face value must go to credit holder\"\n    );\n    require(tx.outputs[2].value >= residual, \"residual to borrower too low\");\n    require(\n      tx.outputs[2].scriptPubKey == new SingleSig(borrowerPk),\n      \"residual must go to borrower\"\n    );\n  }\n\n  // ─── Transfer credit ──────────────────────────────────────────────────────────\n  // Updates creditHolder in the covenant state. Used for secondary market settlement:\n  // a NonInteractiveSwap calls transferCredit to hand the credit position to the buyer\n  // without touching the borrower or the locked collateral.\n  function transferCredit(signature currentHolder, pubkey newHolder) {\n    require(checkSig(currentHolder, creditHolder), \"invalid credit holder\");\n    require(\n      tx.outputs[0].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, newHolder,\n        collateralAmount, debtAmount, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"successor mismatch\"\n    );\n    require(tx.outputs[0].value == tx.input.current.value, \"value must be preserved\");\n  }\n}\n";

export const vault_lending_lending_pool = "// lending_pool.ark\n// Pooled lending market with on-chain supply and borrow token mechanics.\n//\n// supply — anyone deposits liquidity and receives supply tokens (credit claims).\n//          Pool grows by supplyAmount; supply tokens are minted to the supplier.\n//          Token quantity tracks proportional ownership of the pool's assets.\n//\n// borrow — anyone provides collateral, receives borrowed funds and borrow tokens.\n//          Pool value adjusts (loses borrowAmount, gains collateral).\n//          Borrow tokens track outstanding debt obligations.\n//\n// Both functions are permissionless: security comes entirely from on-chain constraints\n// (oracle-attested price, collateral ratio enforcement, asset group token accounting).\n// No keeper signature is required.\n//\n// Token accounting uses asset group delta checks (aggregate mint/burn across the tx)\n// and per-output asset lookup to ensure tokens are routed to the correct recipients.\n//\n// Division note: collateral ratio uses OP_DIV64 (floor toward zero).\n// Both sides consistently floored — no systematic bias at LLTV boundary.\n\nimport \"lending_pool.ark\";\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract LendingPool(\n  pubkey  oraclePk,\n  int     totalSupply,       // total liquidity deposited (satoshis)\n  int     totalBorrowed,     // total outstanding debt (satoshis)\n  int     lltv,              // liquidation LTV in basis points, e.g. 8500 = 85%\n  bytes32 supplyTokenId,     // supply/credit token asset ID — for assetGroups.find()\n  bytes32 supplyTokenCtrlId, // control asset that gates supply token issuance\n  bytes32 borrowTokenId,     // borrow/debt token asset ID — for assetGroups.find()\n  bytes32 borrowTokenCtrlId, // control asset that gates borrow token issuance\n  bytes32 oracleHash         // identifies the oracle feed\n) {\n  // ─── Supply ───────────────────────────────────────────────────────────────────\n  // Permissionless. Anyone deposits liquidity and receives supply tokens.\n  // Caller provides: their pubkey (token destination) and the supply amount.\n  // Pool VTXO grows by supplyAmount; supply tokens are minted 1:1 to the supplier.\n  function supply(pubkey supplierPk, int supplyAmount) {\n    // Supply tokens minted in this transaction\n    let supplyGroup = tx.assetGroups.find(supplyTokenId);\n    require(supplyGroup.delta == supplyAmount, \"supply token delta must match supply amount\");\n    require(supplyGroup.control == supplyTokenCtrlId, \"wrong supply token control asset\");\n    require(\n      tx.inputs[0].assets.lookup(supplyTokenCtrlId) > 0,\n      \"supply control asset must be present at input 0\"\n    );\n\n    // Pool grows by supplyAmount\n    int inputVal = tx.input.current.value;\n    int newPoolVal = inputVal + supplyAmount;\n    require(tx.outputs[0].value == newPoolVal, \"pool must grow by supply amount\");\n\n    // Pool successor with updated totalSupply\n    require(\n      tx.outputs[0].scriptPubKey == new LendingPool(\n        oraclePk, totalSupply + supplyAmount, totalBorrowed, lltv,\n        supplyTokenId, supplyTokenCtrlId, borrowTokenId, borrowTokenCtrlId, oracleHash\n      ),\n      \"pool successor mismatch\"\n    );\n\n    // Supplier receives supply tokens on output 1\n    require(\n      tx.outputs[1].assets.lookup(supplyTokenId) >= supplyAmount,\n      \"supplier output must hold supply tokens\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(supplierPk),\n      \"supply tokens must go to supplier\"\n    );\n  }\n\n  // ─── Borrow ───────────────────────────────────────────────────────────────────\n  // Permissionless (modulo oracle). Borrower provides collateral and takes a loan.\n  // Oracle attests to the current price; collateral ratio is enforced on-chain.\n  // Pool loses borrowAmount and gains collateral; borrow tokens are minted to borrower.\n  function borrow(\n    pubkey  borrowerPk,\n    bytes32 priceHash,\n    signature oracleSig,\n    int price,\n    int borrowAmount,\n    int collateral\n  ) {\n    require(checkSigFromStack(oracleSig, oraclePk, priceHash), \"invalid oracle\");\n\n    // Collateral ratio: (collateral * price / 10000) >= (borrowAmount * 10000 / lltv)\n    int lhs = collateral * price / 10000;\n    int rhs = borrowAmount * 10000 / lltv;\n    require(lhs >= rhs, \"insufficient collateral ratio\");\n\n    // Borrow tokens minted in this transaction\n    let borrowGroup = tx.assetGroups.find(borrowTokenId);\n    require(borrowGroup.delta == borrowAmount, \"borrow token delta must match borrow amount\");\n    require(borrowGroup.control == borrowTokenCtrlId, \"wrong borrow token control asset\");\n    require(\n      tx.inputs[0].assets.lookup(borrowTokenCtrlId) > 0,\n      \"borrow control asset must be present at input 0\"\n    );\n\n    // Pool: loses borrowAmount, gains collateral\n    int inputVal = tx.input.current.value;\n    int newPoolVal = inputVal - borrowAmount + collateral;\n    require(tx.outputs[0].value == newPoolVal, \"pool value mismatch\");\n\n    // Pool successor with updated totalBorrowed\n    require(\n      tx.outputs[0].scriptPubKey == new LendingPool(\n        oraclePk, totalSupply, totalBorrowed + borrowAmount, lltv,\n        supplyTokenId, supplyTokenCtrlId, borrowTokenId, borrowTokenCtrlId, oracleHash\n      ),\n      \"pool successor mismatch\"\n    );\n\n    // Borrower receives funds and borrow tokens on output 1\n    require(tx.outputs[1].value == borrowAmount, \"borrower must receive borrow amount\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk),\n      \"borrowed funds must go to borrower\"\n    );\n  }\n}\n";

export const vault_lending_repay_flow = "// repay_flow.ark\n// Inverse of SupplyFlow. Returns repaid assets from a closed LendingMarket back\n// to VaultCovenant, accreting yield to the vault.\n//\n// The vault's totalAssets increments by returnAmount. Full value flows into the vault:\n// output value == current input value (no value escapes).\n//\n// Yield accrual: returnAmount > original supplyAmount by the interest earned.\n// The caller provides both values; the covenant verifies only conservation and\n// the correct successor state. Interest accounting is settled off-chain.\n//\n// Division note: newVaultAssets = totalAssets + returnAmount (no rounding).\n\nimport \"vault_covenant.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract RepayFlow(\n  pubkey  vaultKeeperPk,\n  pubkey  ownerPk,\n  int     returnAmount,\n  int     totalAssets,\n  int     totalShares\n) {\n  function reclaim(signature vaultKeeperSig) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid vault keeper\");\n\n    // Bind returnAmount to actual input value so vault accounting cannot drift\n    int inputVal = tx.input.current.value;\n    require(inputVal == returnAmount, \"return amount must match input value\");\n\n    int newVaultAssets = totalAssets + returnAmount;\n\n    // Output 0: VaultCovenant with incremented totalAssets; all value flows back\n    require(tx.outputs[0].value == returnAmount, \"full value must flow to vault\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, newVaultAssets, totalShares\n      ),\n      \"vault successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_strategy_fragment = "// strategy_fragment.ark\n// Independent VTXO per strategy. Zero shared state between fragments.\n// Keeper attests to reported amounts via checkSigFromStack.\n\nimport \"strategy_fragment.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract StrategyFragment(\n  pubkey keeperPk,\n  int allocatedAmount,\n  bytes32 strategyId\n) {\n  function allocate(signature keeperSig, int newAmount) {\n    require(checkSig(keeperSig, keeperPk), \"invalid keeper\");\n    require(newAmount > allocatedAmount, \"must increase allocation\");\n    require(\n      tx.outputs[0].scriptPubKey == new StrategyFragment(\n        keeperPk, newAmount, strategyId\n      ),\n      \"successor mismatch\"\n    );\n  }\n\n  function report(signature keeperSig, bytes32 reportHash, int reportedAmount) {\n    require(reportedAmount > 0, \"reported amount must be positive\");\n    require(checkSigFromStack(keeperSig, keeperPk, reportHash), \"invalid keeper\");\n    require(\n      tx.outputs[0].scriptPubKey == new StrategyFragment(\n        keeperPk, reportedAmount, strategyId\n      ),\n      \"successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_supply_flow = "// supply_flow.ark\n// One-shot atomic template. Moves assets from VaultCovenant into a fresh LendingMarket.\n//\n// The vault's totalAssets decrements by supplyAmount. A fresh LendingMarket is created\n// with zero collateral and zero debt, ready for borrow(). Value is conserved:\n// vault output + market output == current input value.\n//\n// Division note: newVaultAssets = totalAssets - supplyAmount (no rounding).\n\nimport \"vault_covenant.ark\";\nimport \"lending_market.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract SupplyFlow(\n  pubkey  vaultKeeperPk,\n  pubkey  ownerPk,\n  pubkey  borrowerPk,\n  pubkey  oraclePk,\n  pubkey  creditHolder,\n  int     supplyAmount,\n  int     lltv,\n  int     totalAssets,\n  int     totalShares,\n  bytes32 collateralAssetId,\n  bytes32 loanAssetId,\n  bytes32 oracleHash\n) {\n  function supply(signature vaultKeeperSig) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid vault keeper\");\n    require(supplyAmount <= totalAssets, \"supply amount exceeds vault assets\");\n\n    int newVaultAssets = totalAssets - supplyAmount;\n    int inputVal = tx.input.current.value;\n    int vaultOut = inputVal - supplyAmount;\n\n    // Output 0: VaultCovenant with decremented totalAssets\n    require(tx.outputs[0].value == vaultOut, \"vault output value mismatch\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, newVaultAssets, totalShares\n      ),\n      \"vault successor mismatch\"\n    );\n\n    // Output 1: fresh LendingMarket seeded with supplyAmount, ready for borrower\n    require(tx.outputs[1].value == supplyAmount, \"market output value mismatch\");\n    require(\n      tx.outputs[1].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n        0, 0, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"market successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_vault_covenant = "// vault_covenant.ark\n// Recursive ERC-4626-style vault. Tracks share accounting and price-per-share (PPS).\n// Only reportYield() can increase totalAssets relative to totalShares.\n// PPS is monotonically non-decreasing: reportYield enforces newTotalAssets >= totalAssets.\n//\n// The covenant is fully non-custodial: every spending path produces a successor\n// VaultCovenant with the same keeperPk and ownerPk. There is no escape hatch.\n//\n// Division note: all arithmetic uses OP_DIV64 (floor toward zero).\n// PPS ratios are computed off-chain; the covenant enforces state transitions only.\n\nimport \"vault_covenant.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract VaultCovenant(\n  pubkey keeperPk,\n  pubkey ownerPk,\n  int totalAssets,\n  int totalShares\n) {\n  function deposit(signature ownerSig, int newTotalAssets, int newTotalShares) {\n    require(checkSig(ownerSig, ownerPk), \"invalid owner\");\n    require(newTotalShares > totalShares, \"shares must increase\");\n    require(newTotalAssets > totalAssets, \"assets must increase\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, newTotalAssets, newTotalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n\n  function withdraw(signature ownerSig, int newTotalAssets, int newTotalShares) {\n    require(checkSig(ownerSig, ownerPk), \"invalid owner\");\n    require(newTotalShares < totalShares, \"shares must decrease\");\n    require(newTotalAssets < totalAssets, \"assets must decrease\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, newTotalAssets, newTotalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n\n  // Only path that can increase PPS.\n  // keeperSig over reportHash prevents intra-block replay.\n  function reportYield(\n    signature keeperSig,\n    bytes32 reportHash,\n    int newTotalAssets\n  ) {\n    require(newTotalAssets >= totalAssets, \"PPS decrease forbidden\");\n    require(checkSigFromStack(keeperSig, keeperPk, reportHash), \"invalid keeper\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, newTotalAssets, totalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n}\n";

